#pragma OPENCL EXTENSION cl_khr_fp32 : enable

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define MAX_PD (3.0e6f)
#define PRECISION 0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI 100.0f
#define FACTOR_CHIP 0.5f

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    const int num_iterations,
    __global const float* power,
    __global const float* temp_in,
    __global float* temp_out,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step
)
{
    int c = get_global_id(0);
    int r = get_global_id(1);

    if (r >= row || c >= col) return;

    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    // We do multiple iterations inside the kernel to reduce overhead
    // We'll ping-pong between two buffers outside this kernel; here just do one iteration at a time.
    // As per the original code, the kernel is called multiple times from host.

    // This kernel computes one iteration at a time; the host will invoke multiple iterations.

    // Compute index
    int idx = r * col + c;

    float temp_val = temp_in[idx];
    float power_val = power[idx];

    // For boundary cells, handle separately
    int r_start = borderRows;
    int c_start = borderCols;
    int r_end = row - borderRows;
    int c_end = col - borderCols;

    float delta = 0.0f;

    // For boundary conditions
    if (r < borderRows || c < borderCols || r >= r_end || c >= c_end)
    {
        // Corners and edges
        if (r == 0 && c == 0) {
            delta = Cap_1 * (power_val +
                (temp_in[1] - temp_val) * Rx_1 +
                (temp_in[col] - temp_val) * Ry_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else if (r == 0 && c == col-1) {
            delta = Cap_1 * (power_val +
                (temp_in[c-1] - temp_val) * Rx_1 +
                (temp_in[c+col] - temp_val) * Ry_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else if (r == row-1 && c == col-1) {
            delta = Cap_1 * (power_val +
                (temp_in[r*col + c -1] - temp_val) * Rx_1 +
                (temp_in[(r-1)*col + c] - temp_val) * Ry_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else if (r == row-1 && c == 0) {
            delta = Cap_1 * (power_val +
                (temp_in[r*col + 1] - temp_val) * Rx_1 +
                (temp_in[(r-1)*col] - temp_val) * Ry_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else if (r == 0) {
            delta = Cap_1 * (power_val +
                (temp_in[c+1] + temp_in[c-1] - 2.0f * temp_val) * Rx_1 +
                (temp_in[col + c] - temp_val) * Ry_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else if (c == col-1) {
            delta = Cap_1 * (power_val +
                (temp_in[(r+1)*col + c] + temp_in[(r-1)*col + c] - 2.0f * temp_val) * Ry_1 +
                (temp_in[r*col + c -1] - temp_val) * Rx_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else if (r == row-1) {
            delta = Cap_1 * (power_val +
                (temp_in[r*col + c +1] + temp_in[r*col + c -1] - 2.0f * temp_val) * Rx_1 +
                (temp_in[(r-1)*col + c] - temp_val) * Ry_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else if (c == 0) {
            delta = Cap_1 * (power_val +
                (temp_in[(r+1)*col] + temp_in[(r-1)*col] - 2.0f * temp_val) * Ry_1 +
                (temp_in[r*col + 1] - temp_val) * Rx_1 +
                (amb_temp - temp_val) * Rz_1);
        }
        else {
            // This case should not happen in boundary check
            delta = 0.0f;
        }
    }
    else
    {
        // interior points
        delta = Cap_1 * (power_val +
            (temp_in[(r+1)*col + c] + temp_in[(r-1)*col + c] - 2.0f * temp_val) * Ry_1 +
            (temp_in[r*col + c +1] + temp_in[r*col + c -1] - 2.0f * temp_val) * Rx_1 +
            (amb_temp - temp_val) * Rz_1);
    }

    temp_out[idx] = temp_val + delta;
}
